#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const int weekend[8] = {6,7,13,14,20,21,27,28};
    while(T--){
        int N; scanf("%d", &N);
        bool hol[31] = {false};
        for(int i=0;i<8;i++) hol[weekend[i]] = true;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            hol[x] = true;
        }
        int cnt = 0;
        for(int d=1; d<=30; d++) if(hol[d]) cnt++;
        printf("%d\n", cnt);
    }
    return 0;
}

