int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const vector<int> weekend = {6,7,13,14,20,21,27,28};
    while(T--){
        int N; cin>>N;
        vector<bool> hol(31,false);
        for(int d: weekend) hol[d]=true;
        for(int i=0;i<N;i++){
            int x; cin>>x; hol[x]=true;
        }
        int cnt=0; for(int d=1; d<=30; ++d) if(hol[d]) ++cnt;
        cout<<cnt<<"\n";
    }
    return 0;
}

