import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        int[] weekend = {6,7,13,14,20,21,27,28};
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            boolean[] hol = new boolean[31];
            for (int d : weekend) hol[d] = true;
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) {
                int x = Integer.parseInt(st.nextToken());
                hol[x] = true;
            }
            int cnt = 0;
            for (int d = 1; d <= 30; d++) if (hol[d]) cnt++;
            sb.append(cnt).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    weekend = {6,7,13,14,20,21,27,28}
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        holidays = set(weekend)
        for _ in range(N):
            holidays.add(int(next(it)))
        out_lines.append(str(len(holidays)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

